module sync_up_counter_20bit(
    input clk,
    input rst,
    input en,
    output reg [19:0] count
);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt)
    if (rst)
        count <= 20'b00000000000000000000;
    else if (en)
        count <= count + 1;

endmodule
